import React from 'react';

const AdminPanel = ({ rooms, threshold, setThreshold }) => {
    const checkedRooms = rooms.filter(r => r.status === 'checked').length;
    const dndRooms = rooms.filter(r => r.status === 'dnd').length;

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">⚙️ Панель управления</h2>

            <div className="admin-stats-grid">
                <div className="stat-card">
                    <span className="stat-value">{checkedRooms}</span>
                    <span className="stat-label">Проверено</span>
                </div>
                <div className="stat-card">
                    <span className="stat-value">{dndRooms}</span>
                    <span className="stat-label">DND</span>
                </div>
            </div>

            <div className="admin-settings-section">
                <h3 style={{fontSize: '14px', marginBottom: '10px'}}>Контроль сроков</h3>
                <p style={{fontSize: '12px', color: '#666'}}>Показывать товары в отчете, если до конца срока осталось:</p>
                <div className="threshold-buttons">
                    {[30, 60, 90, 180].map(days => (
                        <button
                            key={days}
                            className={`t-btn ${threshold === days ? 'active' : ''}`}
                            onClick={() => setThreshold(days)}
                        >
                            {days} дн
                        </button>
                    ))}
                </div>
            </div>

            <button className="btn-download" onClick={() => alert('Экспорт в Excel временно недоступен')}>
                СКАЧАТЬ ОБЩИЙ ОТЧЕТ
            </button>
        </div>
    );
};

export default AdminPanel;
